// --- INICIALIZACIÓN ---
if (!context.get('init')) {
    context.set('init', true);
    context.set('pos', 0);
    context.set('dir', 1);
    context.set('estado', 'STANDBY');
    context.set('bateria', 100); // Empezamos al 100% para simular REQ-OP-002
    context.set('entregas', 0);
    context.set('destino_idx', 0);
    context.set('timer', 0);
}

// --- VARIABLES ---
let pos = context.get('pos');
let dir = context.get('dir');
let bateria = context.get('bateria');
let estado = context.get('estado');
let entregas = context.get('entregas');
let destino_idx = context.get('destino_idx');
let timer = context.get('timer') + 1;

// --- CONFIGURACIÓN DE RUTA ---
const destinos = [150, 350, 550]; // cm
const nombres = ['Habitación 1','Habitación 2','Habitación 3'];
const MAX_POS = 580;

// --- LÓGICA DE ESTADOS ---
if (estado === 'STANDBY') {
    if (timer > 3) { estado = 'EN_RUTA'; timer = 0; }

} else if (estado === 'EN_RUTA') {
    let target = destinos[destino_idx];
    let dx = target - pos;

    // ✅ REQ-OP-003: Velocidad operativa 5 cm/s (±10%)
    // Ajustado de 6 a 5 para cumplir especificación
    if (Math.abs(dx) > 5) {
        pos += 5 * (dx > 0 ? 1 : -1);

        // Simular evasión aleatoria (RIEGO-03)
        if (Math.random() < 0.05) { 
            estado = 'EVASION'; 
            timer = 0; 
        }
    } else {
        pos = target;
        estado = 'VERIFICACION';
        timer = 0;
    }

} else if (estado === 'EVASION') {
    if (timer > 3) { estado = 'EN_RUTA'; timer = 0; }

} else if (estado === 'VERIFICACION') {
    if (timer > 2) { estado = 'ENTREGADO'; timer = 0; }

} else if (estado === 'ENTREGADO') {
    entregas++;
    destino_idx++;
    if (destino_idx < destinos.length) { 
        estado = 'EN_RUTA'; 
    } else { 
        estado = 'RETORNO'; 
    }
    timer = 0;

} else if (estado === 'RETORNO') {
    if (pos > 6) { pos -= 5; } // Velocidad retorno también 5 cm/s
    else { 
        pos = 0; 
        estado = 'STANDBY'; 
        entregas = 0; 
        destino_idx = 0; 
        timer = 0; 
    }
}

// --- SIMULACIÓN DE SENSORES Y BATERÍA ---
// ✅ REQ-OP-002: Batería (simulamos drenaje lento)
if (Math.random() < 0.02) bateria = Math.max(0, bateria - 0.5);

// ✅ RIESGO-03: Sensores (permitimos valores <20cm para activar alertas)
// Antes: Math.max(20, ...) -> Ahora: Math.max(5, ...) para simular obstáculos reales
// --- NUEVA LÓGICA DE SENSORES (Para probar alertas) ---
// --- SENSORES: Priorizar datos reales si existen ---
let frontal;
let usarReal = global.get("usarDistanciaReal") || false;

if (usarReal) {
    // Usar distancia real de la ESP32
    frontal = global.get("distanciaFrontalReal") || 100;
} else {
    // Simular (para cuando no hay ESP32 conectada)
    if (Math.random() < 0.2) {
        frontal = Math.floor(Math.random() * 15) + 5;
    } else {
        frontal = Math.floor(Math.random() * 150) + 30;
    }
}

let lat_izq = Math.max(10, Math.min(50, 30 + Math.round((Math.random() - 0.5) * 20)));
let lat_der = Math.max(10, Math.min(50, 30 + Math.round((Math.random() - 0.5) * 20)));
// Guardar contexto
context.set('pos', pos);
context.set('bateria', bateria);
context.set('estado', estado);
context.set('entregas', entregas);
context.set('destino_idx', destino_idx);
context.set('timer', timer);

// --- SALIDA PAYLOAD ---
const destino_actual = destino_idx < nombres.length ? nombres[destino_idx] : 'Base';
const robot_pct = Math.round((pos / MAX_POS) * 100);

msg.payload = {
    // Datos de navegación
    pos: Math.round(pos), 
    estado: estado, 
    bateria: Math.round(bateria),
    entregas: entregas, 
    destino: destino_actual,
    robot_pct: robot_pct,

    // ✅ Sensores (Crucial para el nodo de Alertas)
    frontal: frontal,
    lat_izq: lat_izq,
    lat_der: lat_der,
    distancia: frontal // 👈 AGREGADO: Para que tu nodo "Verificar Alertas" lo lea
};

return msg;

// Actualizar distancia frontal
if (msg.topic === "sensores_distancia") {
    msg.payload = {
        frontal: msg.payload.frontal || msg.payload.frontal === 0 ? msg.payload.frontal + " cm" : "--",
        izquierda: msg.payload.izquierda || "--",
        derecha: msg.payload.derecha || "--"
    };
    return msg;
}
return null;

const d = msg.payload;

// CASO 1: ACTIVAR SERVOS (después de 10 segundos de carga)
if (d.accion === 'ACTIVAR_SERVOS') {
    const msgMQTT = {
        topic: "bomax/dispenser/comando",
        payload: d.comando  // "H1", "H2", o "H3"
    };

    const hora = new Date().toLocaleTimeString('es-BO', {hour:'2-digit', minute:'2-digit'});
    const entrada = `${hora} ⏱️ Carga completada - Activando servos: ${d.comando}`;
    let log = context.get('log') || [];
    log.unshift(entrada);
    if (log.length > 15) log = log.slice(0,15);
    context.set('log', log);

    const msgLog = { payload: log.join('\n') };

    // RETORNAR: [Influx (null), MQTT, Log]
    return [null, msgMQTT, msgLog];
}

// CASO 2: INICIAR ENTREGA (enviar número de habitaciones)
if (d.accion === 'INICIAR_ENTREGA') {
    context.set('mision_actual', {
        encargado: d.encargado,
        habitaciones: d.habitaciones,
        total: d.total_habitaciones
    });

    const msgMQTT = {
        topic: "bomax/dispenser/comando",
        payload: d.comando_num  // "1H", "2H", o "3H"
    };

    const hora = new Date().toLocaleTimeString('es-BO', {hour:'2-digit', minute:'2-digit'});
    const entrada = `${hora} 🚀 Iniciando entrega - ${d.total_habitaciones} habitación(es): ${d.habitaciones}`;
    let log = context.get('log') || [];
    log.unshift(entrada);
    if (log.length > 15) log = log.slice(0,15);
    context.set('log', log);

    const msgLog = { payload: log.join('\n') };

    // RETORNAR: [Influx (null), MQTT, Log]
    return [null, msgMQTT, msgLog];
}

// CASO 3: ENTREGA POR HABITACIÓN (enviar "a", "b", "c")
if (d.accion === 'ENTREGA_HABITACION') {
    const timestamp = Date.now();
    const medicamento = d.medicamento || "No especificado";
    const horario = d.hora_entrega || "Inmediata";

    // 1. ENVIAR COMANDO MQTT "a", "b", o "c"
    const msgMQTT = {
        topic: "bomax/dispenser/comando",
        payload: d.comando_letra  // "a", "b", o "c"
    };

    // 2. GUARDAR EN INFLUXDB
    const lineProtocol = 
        `entregas,` +
        `paciente=${d.paciente.replace(/ /g,'_')},` +
        `habitacion=${d.habitacion},` +
        `enfermera=${d.encargado.replace(/ /g,'_')} ` +
        `medicamento="${medicamento.replace(/"/g,'\\"')}",` +
        `horario="${horario}",` +
        `estado="ENTREGADA",` +
        `timestamp=${timestamp}000000`;

    const msgInflux = {
        method: 'POST',
        url: 'http://bomax_influxdb:8086/api/v2/write?org=ucb&bucket=robot_data&precision=ns',
        headers: { 
            'Authorization': 'Token bomax-token-2026', 
            'Content-Type': 'text/plain' 
        },
        payload: lineProtocol
    };

    // 3. LOG VISUAL
    const hora = new Date().toLocaleTimeString('es-BO', {hour:'2-digit', minute:'2-digit'});
    const entrada = `${hora} ✓ ${d.encargado} → ${d.habitacion} (${d.paciente}) - 💊 ${medicamento} [${d.comando_letra}]`;

    let log = context.get('log') || [];
    log.unshift(entrada);
    if (log.length > 15) log = log.slice(0,15);
    context.set('log', log);

    const msgLog = { payload: log.join('\n') };

    // RETORNAR: [Influx, MQTT, Log]
    return [msgInflux, msgMQTT, msgLog];
}

return null;

const hora = new Date().toLocaleTimeString('es-BO',{hour:'2-digit',minute:'2-digit',second:'2-digit'});
const d = msg.payload;
let texto = '';
if (typeof d === 'object') {
    const estado = d.estado || d.status || 'UPDATE';
    const pos = d.pos !== undefined ? ` | Pos: ${d.pos}cm` : '';
    const bat = d.bateria !== undefined ? ` | Bat: ${d.bateria}%` : '';
    texto = `${hora} [ROBOT] ${estado}${pos}${bat}`;
} else {
    texto = `${hora} [MQTT] ${d}`;
}
let log = context.get('log') || [];
log.unshift(texto);
if (log.length > 10) log = log.slice(0,10);
context.set('log', log);
return {payload: log.join('\n')};

const d = msg.payload;
const hora = new Date().toLocaleTimeString('es-BO',{hour:'2-digit',minute:'2-digit',second:'2-digit'});
const entrada = `${hora} 🔐 LOGIN: ${d.usuario} (${d.rol})`;

// Guardar usuario en contexto global para usarlo en el formulario
global.set('usuario_activo', d.usuario);
global.set('rol_activo', d.rol);

// Agregar al log
let log = global.get('log_sistema') || [];
log.unshift(entrada);
if (log.length > 20) log = log.slice(0,20);
global.set('log_sistema', log);

// Publicar por MQTT
return {
    payload: JSON.stringify({
        accion: 'LOGIN',
        usuario: d.usuario,
        rol: d.rol,
        timestamp: d.timestamp
    }),
    topic: 'bomax/sistema'
};

// Simulamos lectura de sensores reales
// REQ-OP-003: Velocidad objetivo 5 cm/s (+/- 10% es 4.5 a 5.5)
// Generamos un valor aleatorio dentro del rango válido para probar
let velocidad = (Math.random() * (5.5 - 4.5) + 4.5).toFixed(2);

// Batería que baja muy lentamente para simular REQ-OP-002 (8 horas)
let bateria = msg.payload.bateria || 100;
bateria = bateria - 0.01; // Desgaste simulado

// Timestamp para calcular latencia (REQ-OP-002: < 1s)
let ahora = Date.now();

msg.topic = "bomax/sensores/telemetria";
msg.payload = {
    timestamp_envio: ahora,
    velocidad_cm_s: parseFloat(velocidad),
    bateria_porcentaje: parseFloat(bateria.toFixed(2)),
    estado: "EN_RUTA",
    id_sensor: "pico_01"
};

return msg;

let data = msg.payload;
let time_now = Date.now();

// Cálculo de latencia (Tiempo respuesta - Tiempo envío)
let latencia_ms = time_now - data.timestamp_envio;

// --- VERIFICACIÓN DE REQUISITOS (PDF) ---

// REQ-OP-003: Velocidad 5 cm/s ±10% (Rango 4.5 - 5.5)
let velocidad_ok = (data.velocidad_cm_s >= 4.5 && data.velocidad_cm_s <= 5.5);

// REQ-OP-002: Comunicación < 1000 ms (1 segundo)
let latencia_ok = (latencia_ms < 1000);

// Preparamos el mensaje para guardarlo o mostrarlo
msg.payload = {
    mensaje: `Vel: ${data.velocidad_cm_s} cm/s | Latencia: ${latencia_ms} ms`,
    cumple_velocidad: velocidad_ok,
    cumple_latencia: latencia_ok,
    bateria: data.bateria_porcentaje,
    timestamp_recepcion: new Date().toISOString()
};

// Si hay errores, avisamos en la consola de Node-RED (Debug)
if(!velocidad_ok) node.warn("️ VELOCIDAD FUERA DE RANGO");
if(!latencia_ok) node.error("🚨 LATENCIA ALTA (>1s)");

return msg;

let p = msg.payload;
let estado_text = "SISTEMA OK";
let color = "#27ae60"; // Verde

if (!p.cumple_latencia || !p.cumple_velocidad) {
    estado_text = "ALERTA: FALLA COMUNICACIÓN";
    color = "#e74c3c"; // Rojo
}

msg.payload = `
<div style="background:${color}; color:white; padding:15px; border-radius:8px; text-align:center;">
    <h3 style="margin:0">${estado_text}</h3>
    <p style="margin:5px 0">Latencia: ${p.mensaje.split('|')[1]}</p>
    <p style="margin:5px 0">Batería: ${p.bateria}%</p>
</div>`;
return msg;

// ============================================
// EXTRAER DATOS (puede venir como string u objeto)
// ============================================
var distancia, alerta, voltaje, bateria_baja;

if (typeof msg.payload === 'string') {
    // Intentar parsear como JSON
    try {
        var datos = JSON.parse(msg.payload);

        // Verificar si es dato de batería (tiene voltaje)
        if (datos.voltaje !== undefined) {
            voltaje = datos.voltaje;
            bateria_baja = datos.bateria_baja || false;
            distancia = null;
            alerta = null;
        }
        // Si es dato de obstáculo (tiene distancia)
        else if (datos.distancia !== undefined) {
            distancia = datos.distancia;
            alerta = datos.alerta;
            voltaje = null;
            bateria_baja = null;
        }
        // Mensaje desconocido
        else {
            node.warn("JSON desconocido: " + msg.payload);
            return [null, null, null];
        }
    } catch(e) {
        node.warn("No es JSON válido: " + msg.payload);
        return [null, null, null];
    }
} else if (typeof msg.payload === 'object') {
    // Ya viene como objeto
    voltaje = msg.payload.voltaje;
    bateria_baja = msg.payload.bateria_baja;
    distancia = msg.payload.distancia;
    alerta = msg.payload.alerta;
} else {
    node.error("Tipo de dato desconocido: " + typeof msg.payload);
    return [null, null, null];
}

// ============================================
// ALERTAS COMBINADAS
// ============================================
var alertasArray = [];

// 1. ALERTA DE BATERÍA (si tenemos voltaje)
if (voltaje !== undefined && voltaje !== null) {
    if (voltaje <= 0.5) {
        alertasArray.push({
            nivel: "CRÍTICO",
            mensaje: "🔌 BATERÍA DESCONECTADA - Sin alimentación",
            color: "#95a5a6",
            icono: "🔌",
            timestamp: new Date().toLocaleTimeString()
        });
    } else if (voltaje <= 10.5) {
        alertasArray.push({
            nivel: "ADVERTENCIA",
            mensaje: "⚠️ BATERÍA BAJA: " + voltaje.toFixed(2) + "V - ¡Recargar!",
            color: "#e74c3c",
            icono: "🔋",
            timestamp: new Date().toLocaleTimeString()
        });
    } else if (voltaje >= 11.0) {
        // Batería OK - no agregar alerta
    } else {
        // Zona intermedia (10.5 - 11.0V)
        alertasArray.push({
            nivel: "INFORMACIÓN",
            mensaje: "🔋 Batería: " + voltaje.toFixed(2) + "V",
            color: "#f39c12",
            icono: "🔋",
            timestamp: new Date().toLocaleTimeString()
        });
    }
}

// 2. ALERTA DE OBSTÁCULO (si tenemos distancia)
if (distancia !== undefined && distancia !== null && alerta !== undefined) {
    if (alerta) {
        alertasArray.push({
            nivel: "PELIGRO",
            mensaje: "🚨 Obstáculo detectado a " + distancia + " cm - ¡Frenando!",
            color: "#e74c3c",
            icono: "🚨",
            timestamp: new Date().toLocaleTimeString()
        });
    }
}

// ============================================
// SALIDA 1: Para el Panel de Alertas (ARRAY)
// ============================================
var msgAlerta = {
    payload: alertasArray,
    topic: alertasArray.length > 0 ? "alerta" : "normal"
};

// ============================================
// SALIDA 2: Para debug (ve alertas)
// ============================================
var debugText = "";
if (voltaje !== null && voltaje !== undefined) {
    debugText += "🔋 Batería: " + voltaje.toFixed(2) + "V";
    if (bateria_baja) debugText += " ⚠️";
}
if (distancia !== null && distancia !== undefined) {
    if (debugText) debugText += " | ";
    debugText += "Distancia: " + distancia + " cm";
    if (alerta) debugText += " 🚨";
}

var msgDebug = {
    payload: debugText,
    topic: "debug_alerta",
    distancia: distancia,
    voltaje: voltaje,
    bateria_baja: bateria_baja
};

// ============================================
// SALIDA 3: Para Actualizar Sensor Frontal
// ============================================
var msgDistancia = {
    payload: {
        frontal_real: distancia,
        voltaje_bateria: voltaje,
        bateria_baja: bateria_baja
    },
    topic: "distancia_real"
};

// ============================================
// RETORNAR LAS 3 SALIDAS
// ============================================
return [msgAlerta, msgDebug, msgDistancia];

try {
    const datos = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;

    // 1. Estado para las Cards (Estado, Batería simulada, Habitaciones)
    msg.cards = {
        estado: datos.estado_motor || "EN_RUTA",
        bateria: 98, // Por ahora fijo, luego lo leemos de sensores reales
        habitacion_actual: datos.habitacion || "En tránsito",
        objeto_visto: datos.objeto_detectado ? "✅ SÍ" : "🔍 Buscando..."
    };

    // 2. Log de actividad en tiempo real
    const hora = new Date(datos.timestamp * 1000).toLocaleTimeString('es-BO');
    msg.log = `${hora} | ${datos.estado_motor} | Objeto: ${datos.objeto_detectado ? 'Detectado' : 'No'} | X:${datos.posicion_x || 0}`;

    // 3. Datos crudos para el mapa o debug
    msg.robotData = datos;

    return [msg, {payload: msg.log}, {payload: datos}];
} catch (e) {
    node.error("Error parseando telemetría: " + e);
    return null;
}

// Guardar distancia real en contexto global
if (msg.distancia) {
    global.set("distanciaFrontalReal", msg.distancia);
    global.set("usarDistanciaReal", true);
}
return null; // No pasa mensaje, solo actualiza contexto

const data = msg.payload;

if (data.accion === 'CAMBIAR_MAPA') {
    // Guardar en contexto global
    global.set('mapa_actual', data.mapa);
    global.set('mapa_actual_texto', data.texto);

    // Log de auditoría
    const hora = new Date().toLocaleTimeString('es-BO');
    const log = `${hora} 🔧 ${data.usuario || 'Supervisor'} cambió mapa a: ${data.texto}`;

    let logs = global.get('log_sistema') || [];
    logs.unshift(log);
    if (logs.length > 20) logs = logs.slice(0, 20);
    global.set('log_sistema', logs);

    // Publicar por MQTT para el robot
    return {
        topic: 'bomax/robot/mapa',
        payload: {
            accion: 'CAMBIAR_MAPA',
            mapa: data.mapa,
            texto: data.texto,
            cambiado_por: data.usuario,
            timestamp: data.timestamp
        }
    };
}

return null;

const data = msg.payload;

if (data.accion === 'CONSULTAR_INFLUXDB') {
    // Construir rango de fechas dinámico
    let rangoInicio = '-30d'; // Default: 30 días

    if (data.fechaInicio) {
        // Convertir fecha de input a formato RFC3339
        const fechaIni = new Date(data.fechaInicio + 'T00:00:00Z').toISOString();
        rangoInicio = fechaIni;
    }

    let filtroFecha = '';
    if (data.fechaFin) {
        const fechaFin = new Date(data.fechaFin + 'T23:59:59Z').toISOString();
        filtroFecha = `|> filter(fn: (r) => r["_time"] <= time(v: "${fechaFin}"))`;
    }

    const query = `from(bucket: "robot_data")
  |> range(start: ${rangoInicio})
  |> filter(fn: (r) => r["_measurement"] == "entregas")
  ${filtroFecha}
  |> sort(columns: ["_time"], desc: true)`;

    return {
        method: 'POST',
        url: 'http://bomax_influxdb:8086/api/v2/query?org=ucb',
        headers: {
            'Authorization': 'Token bomax-token-2026',
            'Content-Type': 'application/vnd.flux',
            'Accept': 'application/csv'
        },
        payload: query
    };
}

return null;

// =====================================================
// FORMATEAR DATOS ADMIN - INFLUXDB 2.0 CSV
// =====================================================

const csv = msg.payload;

if (!csv || typeof csv !== "string") {
    node.warn("CSV vacío");
    return {
        payload: {
            accion: "DATOS_INFLUXDB",
            datos: []
        }
    };
}

// -----------------------------------------------------
// Parser CSV robusto
// -----------------------------------------------------
function parseCSVLine(line) {

    const result = [];

    let current = "";
    let inQuotes = false;

    for (let i = 0; i < line.length; i++) {

        const c = line[i];

        if (c === '"') {

            if (
                inQuotes &&
                i + 1 < line.length &&
                line[i + 1] === '"'
            ) {
                current += '"';
                i++;
            } else {
                inQuotes = !inQuotes;
            }

        } else if (c === ',' && !inQuotes) {

            result.push(current);
            current = "";

        } else {

            current += c;

        }
    }

    result.push(current);

    return result;
}

// -----------------------------------------------------
// Leer CSV
// -----------------------------------------------------

const lines = csv.split(/\r?\n/);

let headers = null;

const entregas = {};

// -----------------------------------------------------
// Procesar línea por línea
// -----------------------------------------------------

for (const rawLine of lines) {

    if (!rawLine) continue;

    // Saltar metadata
    if (rawLine.startsWith("#")) continue;

    const cols = parseCSVLine(rawLine);

    // Header de tabla Influx
    if (
        cols.length > 3 &&
        cols.includes("_time") &&
        cols.includes("_field")
    ) {
        headers = cols;
        continue;
    }

    if (!headers) continue;

    if (cols.length !== headers.length) continue;

    const row = {};

    headers.forEach((h, i) => {
        row[h] = cols[i];
    });

    const timestamp = row._time;

    if (!timestamp) continue;

    if (!entregas[timestamp]) {

        entregas[timestamp] = {

            _time: timestamp,

            paciente: row.paciente || "",

            habitacion: row.habitacion || "",

            enfermera: row.enfermera || ""
        };
    }

    // actualizar tags si existen
    if (row.paciente)
        entregas[timestamp].paciente = row.paciente;

    if (row.habitacion)
        entregas[timestamp].habitacion = row.habitacion;

    if (row.enfermera)
        entregas[timestamp].enfermera = row.enfermera;

    // guardar field
    if (
        row._field &&
        row._value !== undefined
    ) {
        entregas[timestamp][row._field] = row._value;
    }
}

// -----------------------------------------------------
// Construir salida final
// -----------------------------------------------------

const resultado = [];

for (const timestamp in entregas) {

    const entrega = entregas[timestamp];

    let jsonData = {};

    // Caso especial:
    // field "value" contiene JSON serializado
    if (entrega.value) {

        try {

            let txt = entrega.value;

            txt = txt.replace(/^"|"$/g, "");

            txt = txt.replace(/""/g, '"');

            jsonData = JSON.parse(txt);

        } catch (err) {

            node.warn(
                "JSON inválido en value: " +
                err.message
            );
        }
    }

    const enfermeroOriginal =
        jsonData.encargado ||
        jsonData.enfermera ||
        entrega.enfermera ||
        "--";

    // Normalizar nombre
    let enfermeroLimpio = enfermeroOriginal
        .replace(/[.,]/g, "")
        .replace(/\s+/g, "_")
        .replace(/_+/g, "_")
        .replace(/^_/, "")
        .trim();

    // Eliminar registros basura
    if (
        enfermeroLimpio === "--" ||
        enfermeroLimpio === "sgssg"
    ){
        continue;
    }
    resultado.push({

        fecha: new Date(timestamp)
            .toLocaleString("es-BO"),

        fechaRaw: timestamp,

        paciente:
            jsonData.paciente ||
            entrega.paciente ||
            "--",

        habitacion:
            jsonData.habitacion ||
            entrega.habitacion ||
            "--",

        enfermero: enfermeroLimpio,

        medicamento:
            jsonData.medicamento ||
            entrega.medicamento ||
            "--",

        horario:
            jsonData.horario ||
            entrega.horario ||
            "--",

        estado:
            jsonData.estado ||
            entrega.estado ||
            "ENTREGADA"
    });
}

// -----------------------------------------------------
// Ordenar más reciente primero
// -----------------------------------------------------

resultado.sort(
    (a, b) =>
        // @ts-ignore
        new Date(b.fechaRaw) -
        // @ts-ignore
        new Date(a.fechaRaw)
);

node.warn(
    "Entregas encontradas: " +
    resultado.length
);
msg.payload = {
    accion: "DATOS_INFLUXDB",
    datos: resultado
};

return msg;
